--- alpha播放表演器
---@class LFightIdleAlphaActor
local LFightIdleAlphaActor = LxClass("LFightIdleAlphaActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LFightIdleAlphaActor:LFightIdleAlphaActor(obj, manager)
	---@type LFightIdleObject
	self._obj = obj

	self._manager = manager

	self._endTime = 0

	self._bWaitEnd = false
end

------------------------------------------------------------------
function LFightIdleAlphaActor:OnRun(time)
	if not self._bWaitEnd then return end
	local preTime = self._timePreCount
	if preTime <= 0 or self._endTime <= time then
		self._obj:GetDpObject():SetAlpha(self._fromAlpha)
		self._bWaitEnd = false
		return
	end

	local time = time - self._startTime - self._calcTime
	while time > preTime do
		time = time - preTime
		self._calcTime = self._calcTime + preTime
	end

	local rate = time / preTime
	rate = rate * 2
	local alpha
	if rate > 1 then
		alpha = Mathf.Lerp(self._fromAlpha, self._toAlpha, rate - 1)
	else
		alpha = Mathf.Lerp(self._toAlpha,self._fromAlpha, rate)
	end

	self._obj:GetDpObject():SetAlpha(alpha)
end

-----------------------------------------------------------------
function LFightIdleAlphaActor:PlayTwinkle(twinkleId, fromAlpha,toAlpha,time, count)
	self._bWaitEnd = true
	self._fromAlpha = fromAlpha
	self._toAlpha = toAlpha
	self._twinkleId = twinkleId

	count = count or 0
	if count <= 0 then count = 1 end
	self._twinkleCount = count

	self._startTime =self:GetTime() -- Time.time
	self._endTime = time + self._startTime

	self._timePreCount = time / count
	self._calcTime = 0
end

function LFightIdleAlphaActor:UpdateAlphaTwinkle(twinkleId,fromAlpha,toAlpha,time, count)
	if not self._bWaitEnd or self._twinkleId ~= twinkleId then
		self:PlayTwinkle(twinkleId ,fromAlpha,toAlpha,time, count)
		return
	end
	self._endTime = time + self:GetTime() --Time.time
end

function LFightIdleAlphaActor:SetAlpha(alpha)
	self._bWaitEnd = false
	self._obj:GetDpObject():SetAlpha(alpha)
end
-----------------------------------------------------------------

function LFightIdleAlphaActor:GetTime()
	return self._manager:GetTime()
end
-----------------------------------------------------------------
function LFightIdleAlphaActor:Destroy()
	self._obj = nil
end

return LFightIdleAlphaActor